import React, { useEffect, useRef } from 'react';

// --- Helper Components for SVG Icons ---
const BioformIcon = () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-8 h-8">
        <path d="M12 2C6.47715 2 2 6.47715 2 12C2 17.5228 6.47715 22 12 22C17.5228 22 22 17.5228 22 12C22 6.47715 17.5228 2 12 2Z" stroke="url(#g_bio)" strokeWidth="1.5" />
        <path d="M12 2C14.2091 2 16 3.79086 16 6C16 8.20914 14.2091 10 12 10C9.79086 10 8 8.20914 8 6C8 3.79086 9.79086 2 12 2Z" stroke="url(#g_bio)" strokeWidth="1.5" strokeOpacity="0.7"/>
        <defs><linearGradient id="g_bio" x1="0" y1="0" x2="24" y2="24"><stop stopColor="#FF7A00"/><stop offset="1" stopColor="#32CD32"/></linearGradient></defs>
