const MyceliumIcon = () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-8 h-8">
       <path d="M12 2V6" stroke="url(#g_myc)" strokeWidth="1.5" strokeLinecap="round"/>
       <path d="M12 18V22" stroke="url(#g_myc)" strokeWidth="1.5" strokeLinecap="round"/>
