       <path d="M16 16L19 19" stroke="url(#g_myc)" strokeWidth="1.5" strokeLinecap="round"/>
       <path d="M2 12H6" stroke="url(#g_myc)" strokeWidth="1.5" strokeLinecap="round"/>
       <path d="M18 12H22" stroke="url(#g_myc)" strokeWidth="1.5" strokeLinecap="round"/>
       <path d="M8 16L5 19" stroke="url(#g_myc)" strokeWidth="1.5" strokeLinecap="round"/>
       <path d="M19 5L16 8" stroke="url(#g_myc)" strokeWidth="1.5" strokeLinecap="round"/>
