const PhotosynthIcon = () => (
    <svg width="24" height="24" viewBox="0 0 24 24" fill="none" xmlns="http://www.w3.org/2000/svg" className="w-8 h-8">
        <path d="M12 18C15.3137 18 18 15.3137 18 12C18 8.68629 15.3137 6 12 6C8.68629 6 6 8.68629 6 12C6 15.3137 8.68629 18 12 18Z" stroke="url(#g_photo)" strokeWidth="1.5"/>
        <path d="M22 12C22 17.5228 17.5228 22 12 22C6.47715 22 2 17.5228 2 12C2 6.47715 6.47715 2 12 2" stroke="url(#g_photo)" strokeWidth="1.5" strokeLinecap="round"/>
        <defs><linearGradient id="g_photo" x1="0" y1="0" x2="24" y2="24"><stop stopColor="#FF7A00"/><stop offset="1" stopColor="#32CD32"/></linearGradient></defs>
    </svg>
);


/**
 * The FuturisticHero component contains the UI and interactive logic for the hero section,
 * including the canvas background animation and parallax effects.
 */
export default function FuturisticHero() {
    const canvasRef = useRef(null);
    const contentWrapperRef = useRef(null);
    const mousePos = useRef({ x: undefined, y: undefined });
    let frame = useRef(0);

    // Effect for the "Aqueous Mesh" background
    useEffect(() => {
        const canvas = canvasRef.current;
        const ctx = canvas.getContext('2d');
        let animationFrameId;
        const points = [];
        const gridSize = 30;

        class Point {
            constructor(x, y) {
                this.x = x;
                this.y = y;
                this.originX = x;
                this.originY = y;
                this.z = 0;
            }
            update() {
                if (mousePos.current.x === undefined) {
                    this.x += (this.originX - this.x) * 0.1;
                    this.y += (this.originY - this.y) * 0.1;
                    this.z += (0 - this.z) * 0.1;
                    return;
                }
                const dx = this.x - mousePos.current.x;
                const dy = this.y - mousePos.current.y;
                const dist = Math.sqrt(dx * dx + dy * dy);
                const maxDist = 150;

                if (dist < maxDist) {
                    const angle = Math.atan2(dy, dx);
                    const force = (maxDist - dist) / maxDist;
                    this.x += Math.cos(angle) * force * 5;
                    this.y += Math.sin(angle) * force * 5;
                    this.z = force * 20;
                }

                // Return to origin
                this.x += (this.originX - this.x) * 0.1;
                this.y += (this.originY - this.y) * 0.1;
                this.z += (0 - this.z) * 0.1;
            }
        }

        const init = () => {
            points.length = 0;
            const cols = Math.ceil(canvas.width / gridSize);
            const rows = Math.ceil(canvas.height / gridSize);
            for (let i = 0; i <= cols; i++) {
                for (let j = 0; j <= rows; j++) {
                    points.push(new Point(i * gridSize, j * gridSize));
                }
            }
        };

        const animate = () => {
            ctx.clearRect(0, 0, canvas.width, canvas.height);
            frame.current++;

            const cols = Math.ceil(canvas.width / gridSize);
            const rows = Math.ceil(canvas.height / gridSize);

            points.forEach(p => p.update());

            const gradient = ctx.createLinearGradient(0, 0, canvas.width, canvas.height);
            gradient.addColorStop(0, "rgba(255, 122, 0, 0.5)");
            gradient.addColorStop(1, "rgba(50, 205, 50, 0.5)");
            ctx.strokeStyle = gradient;

            for (let i = 0; i < cols; i++) {
                for (let j = 0; j < rows; j++) {
                    const p1 = points[i * (rows + 1) + j];
                    const p2 = points[i * (rows + 1) + (j + 1)];
                    const p3 = points[(i + 1) * (rows + 1) + j];

                    if (p1 && p2) {
                        ctx.beginPath();
                        ctx.moveTo(p1.x, p1.y);
                        ctx.lineTo(p2.x, p2.y);
                        ctx.lineWidth = 1 + p1.z / 10;
                        ctx.stroke();
                    }
                    if (p1 && p3) {
                         ctx.beginPath();
                        ctx.moveTo(p1.x, p1.y);
                        ctx.lineTo(p3.x, p3.y);
                        ctx.lineWidth = 1 + p1.z / 10;
                        ctx.stroke();
                    }
                }
            }

            animationFrameId = requestAnimationFrame(animate);
        };

        const resizeCanvas = () => {
            canvas.width = window.innerWidth;
            canvas.height = window.innerHeight;
            init();
        };

        const handleMouseMove = (e) => {
            mousePos.current = { x: e.clientX, y: e.clientY };
        };

        const handleMouseOut = () => {
            mousePos.current = { x: undefined, y: undefined };
        }

        window.addEventListener('resize', resizeCanvas);
        window.addEventListener('mousemove', handleMouseMove);
        window.addEventListener('mouseout', handleMouseOut);

        resizeCanvas();
        animate();

        return () => {
            window.removeEventListener('resize', resizeCanvas);
            window.removeEventListener('mousemove', handleMouseMove);
            window.removeEventListener('mouseout', handleMouseOut);
            cancelAnimationFrame(animationFrameId);
        };
    }, []);

     // Effect for handling the content parallax
    useEffect(() => {
        const contentWrapper = contentWrapperRef.current;
        if (!contentWrapper) return;
        const handleMouseMoveForParallax = (e) => {
            const { clientX, clientY } = e;
            const x = (clientX / window.innerWidth) - 0.5;
            const y = (clientY / window.innerHeight) - 0.5;
            const parallaxFactor = 20;
            contentWrapper.style.transform = `translate3d(${-x * parallaxFactor}px, ${-y * parallaxFactor}px, 0) perspective(1000px)`;
        };
        window.addEventListener('mousemove', handleMouseMoveForParallax);
        return () => {
            window.removeEventListener('mousemove', handleMouseMoveForParallax);
        };
    }, []);

    return (
        <div className="w-full h-screen flex items-center justify-center p-4 overflow-hidden">
            <canvas id="aqueous-canvas" ref={canvasRef}></canvas>
            <div className="content-wrapper w-full max-w-7xl mx-auto flex flex-col h-full" ref={contentWrapperRef}>
                <header className="py-6 px-4">
                    <nav className="flex justify-between items-center">
                        <a href="#" className="text-2xl font-bold main-glow tracking-wide">GAIA</a>
                        <div className="hidden md:flex items-center space-x-8 text-sm font-medium">
                            <a href="#" className="nav-link">Ecosystems</a>
                            <a href="#" className="nav-link">Research</a>
                            <a href="#" className="nav-link">Symbiosis</a>
                            <a href="#" className="nav-link">Seed</a>
                        </div>
                        <button className="px-5 py-2 rounded-lg text-sm btn-secondary hidden md:block">
                            Access Nursery
                        </button>
                         <button className="md:hidden text-gray-700">
                            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 6h16M4 12h16m-7 6h7"></path></svg>
                        </button>
                    </nav>
                </header>
                <main className="flex-grow flex flex-col items-center justify-center text-center px-4">
                    <div className="max-w-4xl">
                        <h1 className="text-4xl sm:text-6xl lg:text-7xl font-bold tracking-tight mb-4 main-glow">
                            The Gaia Protocol
                        </h1>
                        <p className="text-lg sm:text-xl text-gray-600 max-w-3xl mx-auto mb-8">
                            A decentralized framework for global environmental synthesis, powered by a living, self-organizing data network.
                        </p>
                        <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                            <button className="w-full sm:w-auto px-8 py-4 rounded-lg btn-primary">
                                Begin Cultivation &rarr;
                            </button>
                            <button className="w-full sm:w-auto px-8 py-4 rounded-lg btn-secondary">
                                View Genesis Block
                            </button>
                        </div>
                    </div>
                    <div className="w-full mt-16 lg:mt-24 grid grid-cols-1 md:grid-cols-3 gap-6">
                        <div className="bio-card p-6 rounded-2xl text-left">
                            <div className="flex items-center gap-4">
                                <BioformIcon />
                                <h3 className="text-lg font-bold text-gray-800">Bioform Compiler</h3>
                            </div>
                            <p className="mt-2 text-sm text-gray-600">Translate complex ecological data into executable, adaptive digital organisms.</p>
                        </div>
                        <div className="bio-card p-6 rounded-2xl text-left">
                            <div className="flex items-center gap-4">
                                <MyceliumIcon />
                                <h3 className="text-lg font-bold text-gray-800">Mycelium Network</h3>
                            </div>
                            <p className="mt-2 text-sm text-gray-600">A resilient, distributed mesh network that mimics fungal intelligence for data routing.</p>
                        </div>
                        <div className="bio-card p-6 rounded-2xl text-left">
                            <div className="flex items-center gap-4">
                                <PhotosynthIcon />
                                <h3 className="text-lg font-bold text-gray-800">Photosynth Chain</h3>
                            </div>
                            <p className="mt-2 text-sm text-gray-600">A novel blockchain that generates energy and value from verified carbon sequestration.</p>
                        </div>
                    </div>
                </main>
            </div>
        </div>
    );
}
